head.script:
scwin.vCurDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");  // 서버를 기준으로 현재 날짜 반환
scwin.vQryStDt = scwin.vCurDate.substring(0, 6) + "01";  // 조회시작일자(현재 날짜가 포함된 달의 시작 일자)
scwin.vQryEndDt = scwin.vCurDate.substring(0, 6) + new Date(scwin.vCurDate.substring(0, 4), scwin.vCurDate.substring(4, 6) , 0).getDate();  // 조회종료일자(현재 날짜가 포함된 달의 마지막 일자)
//scwin.strPreDate = WebSquare.date.dateAdd(scwin.vCurDate, -2);
scwin.strPreDate = $c.date.addMonth(scwin.vCurDate, -1);


scwin.hid_kcomcd = "DBEX";
scwin.iogb = "";

scwin.onpageload = function() {
    scwin.params = $c.data.getParameter();
    console.log(scwin.params);

    if(scwin.params.iogb != "" && scwin.params.iogb != null) {
        scwin.iogb = scwin.params.iogb; 
    } else {
        scwin.iogb = scwin.params.menuInfo.menuParam.iogb;
    }
    //scwin.iogb = scwin.params.menuInfo.menuParam.iogb;
    console.log(scwin.iogb);
};

scwin.onUdcCompleted = function() {
    $p.setTimeout(function() {
        scwin.f_DefaultValue();

    }, {"delay":100});
};

//-------------------------------------------------------------------------
// 조회 조건 지우기
//-------------------------------------------------------------------------
scwin.f_FieldClear = function ()  {
    $c.gus.cfInitObjects(tb_retrieve,null);
    cnd_lc_iogb.focus();
}

//-------------------------------------------------------------------------
// function name : f_DefaultValue
// function desc : 화면 open시 초기  데이타 setting
//-------------------------------------------------------------------------
scwin.f_DefaultValue = function () {
    cnd_lc_iogb.setValue(scwin.iogb);
    if (cnd_lc_iogb.getValue() == "I") {	//Import
        io_gb.setValue("Arrival Date:");
    }else{
        io_gb.setValue("Onboard Date:");
    }

    cnd_ica_ondtFrom.setValue(scwin.strPreDate);
    cnd_ica_ondtTo.setValue(scwin.vCurDate);
}

//-------------------------------------------------------------------------
// 날짜설정
//-------------------------------------------------------------------------
scwin.f_SetDate = function (pSetType, pDayCnt) {
    //유형 1:현재일, 2:이전일, 3:이후일

    var vReturnDate = "";

    if(pSetType=="1"){
        //vReturnDate = new Date().format("YYYYMMDD");
        vReturnDate = scwin.vCurDate;
    }else if(pSetType=="2"){
        //vReturnDate = new Date().before(0, 0, pDayCnt).format("YYYYMMDD");
        vReturnDate = WebSquare.date.dateAdd(scwin.vCurDate, -1);
    }else if(pSetType=="3"){
        //vReturnDate = new Date().after(0, 0, pDayCnt).format("YYYYMMDD");
        vReturnDate = WebSquare.date.dateAdd(scwin.vCurDate, 1);
    }

    return vReturnDate;
}



//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
    dma_search.set("kcomcd",scwin.hid_kcomcd);	//대표거래처 코드

    if(cnd_ica_ondtFrom.getValue().trim()== '' || cnd_ica_ondtTo.getValue().trim()==''){
        $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, Array("ETD"));
        cnd_ica_ondtFrom.focus();
        return false; 
    }	
    var chk = $c.gus.cfIsAfterDate(cnd_ica_ondtFrom.getValue(), cnd_ica_ondtTo.getValue())	
    if (!chk){
        $c.gus.cfAlertMsg(E_MSG_CM_ERR_039);  // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
        cnd_ica_ondtFrom.focus();
        return false;
    }	    
    //tr_retrieve.post();
    $c.sbm.execute(sbm_retrieve);
}

scwin.f_CustemerBookingDetail = function (){
    //var condition = "?";
    var row = ds_CustomerBookingInfo.getRowPosition();
    var strExpertDetailUrl = "/ui/il/airout/aobk/ar_101_01_01b.xml";
    var strImportDetailUrl = "/ui/il/airinb/aibk/ar_201_01_01b.xml";


    if(row > -1){
        //선택된 오더 정보 : 오더번호 / 화물구분
        var v_kmcom = ds_CustomerBookingInfo.getCellData(row, "kcomcd");
        var v_srno 	= ds_CustomerBookingInfo.getCellData(row, "srno");

        var param = {
            kcomcd : v_kmcom,
            srno : v_srno
        }

        //condition += "kcomcd=" + v_kmcom + "&srno=" + v_srno;
        if(cnd_lc_iogb.getValue() == "O"){
            //cfTabMenuUpdate(strExpertDetailUrl+condition,"Export Customer Booking");
            $c.win.openMenu("Export Customer Booking", strExpertDetailUrl,"ar_101_01_01b.xml",param,{openAction : "exist"});
        } else {
            //cfTabMenuUpdate(strImportDetailUrl+condition,"Import Customer Booking");
            $c.win.openMenu("Import Customer Booking", strImportDetailUrl,"ar_201_01_01b.xml",param,{openAction : "exist"});
        }
    } else {
        $c.win.alert(E_MSG_CM_ERR_056);
        //$c.win.alert("Nothing has been selected.");
        return;
    }
}

//-------------------------------------------------------------------------
//ilpopupdefine 열기
//-------------------------------------------------------------------------
scwin.f_PopUp = function ( pWinCloseTF, pAllSearchTF, pNoDataCloseTF) {

    var rtnList = new Array();
    var code = cnd_ed_dscd.getValue().trim();
    var name = cnd_ed_dsnm.getValue();

    cnd_ed_dscd.setValue("");
    cnd_ed_dsnm.setValue("");

    udc_dscd.ilCommonPopUp(scwin.callbackAirPortCode,
                            code,  
                            name, 
                            pWinCloseTF,
                            '2',
                            'Port Code, Port Name', 
                            '130,300', 
                            "3,4,5,6,7,8,9,10", 
                            null,
                            '500', '500',
                            null, null, null,
                            pAllSearchTF,
                            'Destination Search, Port Code, Port Name',
                            pNoDataCloseTF);

        //cfSetReturnValue(rtnList, cnd_ed_dscd, cnd_ta_dsnm);

}

//공통팝업 열기
scwin.f_OpenCommonPopUp = function ( pWinCloseTF, pAllSearchTF, pNoDataCloseTF) {
    var rtnList			= new Array();

    var code = cnd_ed_sacd.getValue().trim();
    var name = cnd_ed_sanm.getValue();

    cnd_ed_sacd.setValue("");
    cnd_ed_sanm.setValue("");
    console.log("code : "+ code);

    udc_sacd.ilCommonPopUp(scwin.callbackEmpInfo
                            ,code
                            ,name
                            ,pWinCloseTF
                            ,'2'
                            ,"Code, Name"
                            ,'80,230'
                            ,"3,4,5,6,7,8,9,10"
                            ,null ,null ,null ,null ,null ,null
                            ,pAllSearchTF
                            ,"Salesman,Code,Name"
                            ,pNoDataCloseTF
                            ); 

                //cfSetReturnValue(rtnList, cnd_ed_sacd, cnd_ta_sanm);

}	

scwin.callbackAirPortCode = function (rtnList) {
    console.log(rtnList);
    $c.gus.cfSetReturnValue(rtnList, cnd_ed_dscd, cnd_ed_dsnm);
}

scwin.callbackEmpInfo = function (rtnList) {
    console.log(rtnList);
    $c.gus.cfSetReturnValue(rtnList, cnd_ed_sacd, cnd_ed_sanm);
}

scwin.gr_CustomerBookingInfo_oncelldblclick = function (rowIndex, columnIndex, columnId) {
    scwin.f_CustemerBookingDetail();	
};

scwin.btn_retrieve_onclick = function (e) {
    scwin.f_Retrieve();
};

scwin.btn_fieldClear_onclick = function (e) {
    scwin.f_FieldClear();
};

scwin.udc_dscd_onclickEvent = function (e) {
