};

scwin.udc_sacd_onblurCodeEvent = function (e) {
	var strClntNo = cnd_ed_sacd.getValue().trim() ;

	//if (cnd_ed_sacd.Modified ) {
		if (strClntNo.length > 0) {	
			cnd_ed_sanm.setValue("");
			scwin.f_OpenCommonPopUp("T", "F","F");
		} else {
