scwin.cnd_lc_iogb_onviewchange = function (info) {
	if (cnd_lc_iogb.getValue() == "I") {
		io_gb.setValue("Arrival Date:");
	} else {
        io_gb.setValue("Onboard Date:");
	}
};

scwin.sbm_retrieve_submitdone = async function (e) {
	if( ds_CustomerBookingInfo.getRowCount() == 0 ){
		//$c.win.alert(E_MSG_CM_ERR_003);	//해당되는 자료가 존재하지 않습니다.
        await $c.win.alert("No data found./Could not find any relevant data.");
		cnd_ica_ondtFrom.focus();	
	}else{
		//processFlag = "Exist";
	}
    spa_cnt.setValue(ds_CustomerBookingInfo.getRowCount());
};

//-------------------------------------------------------------------------
// 대문자 입력
//-------------------------------------------------------------------------
scwin.onkeyup = function (e) {
    this.setValue(e.target.value.toUpperCase());
};

scwin.excelDown = async function () {

    const options = {
        fileName : "프로그램목록.xlsx", //[default : excel.xlsx] options.fileName 값이 없을 경우 default값 세팅
        sheetName : "프로그램목록",
        startRowIndex : 0,
        startColumnIndex : 0,
    };

    // 타이틀
    const infoArr = [];

    var chk = await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?");

    if(chk){
        $c.data.downloadGridViewExcel(gr_CustomerBookingInfo, options, infoArr);
    }
}
